// ─── AdminPage.tsx — Gestion des utilisateurs ─────────────────────────────
import { useState, useEffect } from 'react';
import { motion } from 'framer-motion';
import { Shield, Users, ArrowLeft, Trash2, RefreshCw, CheckCircle, XCircle } from 'lucide-react';
import { apiClient } from '../lib/api';
import { useAuth } from '../contexts/AuthContext';

interface UserAdmin {
  id: number;
  email: string;
  plan: string;
  is_active: boolean;
  scan_count: number;
  created_at: string;
}

interface Stats {
  total_users: number;
  active_users: number;
  pro_users: number;
  free_users: number;
  total_scans: number;
}

interface Props {
  onBack?: () => void;
}

const PLAN_COLORS: Record<string, string> = {
  free:  'text-slate-400 bg-slate-800 border-slate-700',
  pro:   'text-cyan-400 bg-cyan-500/10 border-cyan-500/30',
  team:  'text-purple-400 bg-purple-500/10 border-purple-500/30',
};

export default function AdminPage({ onBack }: Props) {
  const { user } = useAuth();
  const [users, setUsers]     = useState<UserAdmin[]>([]);
  const [stats, setStats]     = useState<Stats | null>(null);
  const [loading, setLoading] = useState(true);
  const [error, setError]     = useState('');
  const [updating, setUpdating] = useState<number | null>(null);
  const [search, setSearch]   = useState('');

  const fetchData = async () => {
    setLoading(true);
    setError('');
    try {
      const [usersRes, statsRes] = await Promise.all([
        apiClient.get('/admin/users'),
        apiClient.get('/admin/stats'),
      ]);
      setUsers(usersRes.data);
      setStats(statsRes.data);
    } catch (e: any) {
      setError(e?.response?.data?.detail || 'Erreur de chargement');
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => { fetchData(); }, []);

  const updatePlan = async (userId: number, plan: string) => {
    setUpdating(userId);
    try {
      const res = await apiClient.patch(`/admin/users/${userId}`, { plan });
      setUsers(prev => prev.map(u => u.id === userId ? res.data : u));
    } catch (e: any) {
      alert(e?.response?.data?.detail || 'Erreur');
    } finally {
      setUpdating(null);
    }
  };

  const toggleActive = async (userId: number, is_active: boolean) => {
    setUpdating(userId);
    try {
      const res = await apiClient.patch(`/admin/users/${userId}`, { is_active });
      setUsers(prev => prev.map(u => u.id === userId ? res.data : u));
    } catch (e: any) {
      alert(e?.response?.data?.detail || 'Erreur');
    } finally {
      setUpdating(null);
    }
  };

  const deleteUser = async (userId: number, email: string) => {
    if (!confirm(`Supprimer ${email} et tout son historique ?`)) return;
    setUpdating(userId);
    try {
      await apiClient.delete(`/admin/users/${userId}`);
      setUsers(prev => prev.filter(u => u.id !== userId));
    } catch (e: any) {
      alert(e?.response?.data?.detail || 'Erreur');
    } finally {
      setUpdating(null);
    }
  };

  const filtered = users.filter(u =>
    u.email.toLowerCase().includes(search.toLowerCase())
  );

  return (
    <div className="min-h-screen bg-slate-950 text-slate-100">

      {/* Nav */}
      <nav className="border-b border-slate-800/70 bg-slate-950/80 backdrop-blur-sm sticky top-0 z-20">
        <div className="max-w-6xl mx-auto px-4 py-3 flex items-center justify-between">
          <div className="flex items-center gap-3">
            <button onClick={onBack} className="text-slate-500 hover:text-white transition p-1 rounded-lg hover:bg-slate-800">
              <ArrowLeft size={16} />
            </button>
            <div className="flex items-center gap-2">
              <div className="p-1.5 rounded-lg bg-cyan-500/10 border border-cyan-500/20">
                <Shield size={16} className="text-cyan-400" />
              </div>
              <span className="font-bold text-white font-mono tracking-tight">
                We<span className="text-cyan-400">zea</span>
              </span>
            </div>
            <span className="text-slate-600 font-mono text-xs">/ Admin</span>
          </div>
          <button onClick={fetchData} className="flex items-center gap-1.5 text-xs text-slate-500 hover:text-white transition font-mono px-3 py-1.5 rounded-lg hover:bg-slate-800">
            <RefreshCw size={12} />
            Actualiser
          </button>
        </div>
      </nav>

      <div className="max-w-6xl mx-auto px-4 py-8">

        {/* Stats */}
        {stats && (
          <motion.div
            initial={{ opacity: 0, y: 12 }}
            animate={{ opacity: 1, y: 0 }}
            className="grid grid-cols-2 sm:grid-cols-5 gap-3 mb-8"
          >
            {[
              { label: 'Utilisateurs', value: stats.total_users, color: 'text-white' },
              { label: 'Actifs', value: stats.active_users, color: 'text-emerald-400' },
              { label: 'Free', value: stats.free_users, color: 'text-slate-400' },
              { label: 'Pro/Team', value: stats.pro_users, color: 'text-cyan-400' },
              { label: 'Scans total', value: stats.total_scans, color: 'text-purple-400' },
            ].map(s => (
              <div key={s.label} className="bg-slate-900 border border-slate-800 rounded-xl p-4 text-center">
                <p className={`text-2xl font-black font-mono ${s.color}`}>{s.value}</p>
                <p className="text-slate-500 text-[10px] font-mono mt-0.5">{s.label}</p>
              </div>
            ))}
          </motion.div>
        )}

        {/* Header + search */}
        <div className="flex items-center justify-between mb-4 gap-4">
          <div className="flex items-center gap-2">
            <Users size={16} className="text-slate-500" />
            <h1 className="text-white font-mono font-bold text-sm">Utilisateurs</h1>
          </div>
          <input
            type="text"
            placeholder="Rechercher un email..."
            value={search}
            onChange={e => setSearch(e.target.value)}
            className="bg-slate-800 border border-slate-700 rounded-lg px-3 py-1.5 text-xs text-white font-mono focus:outline-none focus:border-cyan-500 transition w-64"
          />
        </div>

        {/* Error */}
        {error && (
          <div className="mb-4 bg-red-500/10 border border-red-500/20 rounded-xl px-4 py-3 text-red-400 text-xs font-mono">
            {error}
          </div>
        )}

        {/* Table */}
        {loading ? (
          <div className="flex items-center justify-center py-20">
            <div className="w-6 h-6 border-2 border-cyan-500/30 border-t-cyan-500 rounded-full animate-spin" />
          </div>
        ) : (
          <motion.div
            initial={{ opacity: 0 }}
            animate={{ opacity: 1 }}
            className="bg-slate-900 border border-slate-800 rounded-2xl overflow-hidden"
          >
            <table className="w-full">
              <thead>
                <tr className="border-b border-slate-800">
                  <th className="text-left px-4 py-3 text-xs text-slate-500 font-mono uppercase tracking-wider">Email</th>
                  <th className="text-left px-4 py-3 text-xs text-slate-500 font-mono uppercase tracking-wider">Plan</th>
                  <th className="text-left px-4 py-3 text-xs text-slate-500 font-mono uppercase tracking-wider hidden sm:table-cell">Scans</th>
                  <th className="text-left px-4 py-3 text-xs text-slate-500 font-mono uppercase tracking-wider hidden md:table-cell">Inscrit le</th>
                  <th className="text-left px-4 py-3 text-xs text-slate-500 font-mono uppercase tracking-wider">Statut</th>
                  <th className="px-4 py-3"></th>
                </tr>
              </thead>
              <tbody>
                {filtered.length === 0 ? (
                  <tr><td colSpan={6} className="text-center py-12 text-slate-600 font-mono text-sm">Aucun utilisateur</td></tr>
                ) : filtered.map((u) => (
                  <tr
                    key={u.id}
                    className={`border-b border-slate-800/50 hover:bg-slate-800/30 transition ${updating === u.id ? 'opacity-50' : ''}`}
                  >
                    {/* Email */}
                    <td className="px-4 py-3">
                      <div className="flex items-center gap-2">
                        <div className="w-7 h-7 rounded-full bg-cyan-500/10 border border-cyan-500/20 flex items-center justify-center text-cyan-400 text-xs font-bold shrink-0">
                          {u.email[0].toUpperCase()}
                        </div>
                        <span className="text-xs text-slate-300 font-mono truncate max-w-[180px]">{u.email}</span>
                      </div>
                    </td>

                    {/* Plan */}
                    <td className="px-4 py-3">
                      <select
                        value={u.plan}
                        onChange={e => updatePlan(u.id, e.target.value)}
                        disabled={updating === u.id || u.id === user?.id}
                        className={`text-xs font-mono px-2 py-1 rounded-lg border cursor-pointer focus:outline-none transition ${PLAN_COLORS[u.plan] || PLAN_COLORS.free} bg-transparent disabled:cursor-not-allowed`}
                      >
                        <option value="free" className="bg-slate-900">Free</option>
                        <option value="pro" className="bg-slate-900">Pro</option>
                        <option value="team" className="bg-slate-900">Team</option>
                      </select>
                    </td>

                    {/* Scans */}
                    <td className="px-4 py-3 hidden sm:table-cell">
                      <span className="text-xs text-slate-400 font-mono">{u.scan_count}</span>
                    </td>

                    {/* Date */}
                    <td className="px-4 py-3 hidden md:table-cell">
                      <span className="text-xs text-slate-500 font-mono">
                        {new Date(u.created_at).toLocaleDateString('fr-FR')}
                      </span>
                    </td>

                    {/* Statut */}
                    <td className="px-4 py-3">
                      <button
                        onClick={() => toggleActive(u.id, !u.is_active)}
                        disabled={updating === u.id || u.id === user?.id}
                        title={u.is_active ? 'Désactiver' : 'Activer'}
                        className="disabled:cursor-not-allowed"
                      >
                        {u.is_active
                          ? <CheckCircle size={16} className="text-emerald-400 hover:text-emerald-300 transition" />
                          : <XCircle size={16} className="text-red-400 hover:text-red-300 transition" />
                        }
                      </button>
                    </td>

                    {/* Actions */}
                    <td className="px-4 py-3">
                      {u.id !== user?.id && (
                        <button
                          onClick={() => deleteUser(u.id, u.email)}
                          disabled={updating === u.id}
                          className="text-slate-600 hover:text-red-400 transition disabled:cursor-not-allowed"
                          title="Supprimer"
                        >
                          <Trash2 size={14} />
                        </button>
                      )}
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          </motion.div>
        )}
      </div>
    </div>
  );
}
